+function isValidRedirectUrl(url) {
+  // Only allow relative URLs (same origin) to prevent open redirect and XSS
+  if (!url) return false
+  try {
+    // Block javascript: URLs, data: URLs, and other dangerous schemes
+    if (/^[a-zA-Z][a-zA-Z0-9+\-.]*:/.test(url) && !/^https?:\/\//i.test(url)) {
+      return false
+    }
+    // If it's an absolute URL, ensure it's the same origin
+    if (/^https?:\/\//i.test(url)) {
+      const parsed = new URL(url)
+      return parsed.origin === window.location.origin
+    }
+    // Allow relative URLs starting with /
+    return url.startsWith('/')
+  } catch (e) {
+    return false
+  }
+}
