+const { execSync } = require('child_process');
+const path = require('path');
+const fs = require('fs');
+
+function verifyAllSignatures(packageDir) {
+  const files = fs.readdirSync(packageDir, { recursive: true });
+  const executableExtensions = ['.exe', '.dll', '.node'];
+  
+  for (const file of files) {
+    const filePath = path.join(packageDir, file);
+    const ext = path.extname(file).toLowerCase();
+    
+    if (executableExtensions.includes(ext)) {
+      if (!fs.statSync(filePath).isFile()) continue;
+      
+      try {
+        execSync(`powershell -Command "Get-AuthenticodeSignature '${filePath}' | Where-Object { $_.Status -eq 'Valid' }"`, {
+          stdio: 'pipe'
+        });
+      } catch (e) {
+        throw new Error(`Signature validation failed for ${filePath}: ${e.message}`);
+      }
+    }
+  }
+  
+  return true;
+}
+
+module.exports = { verifyAllSignatures };

