+import { describe, it } from 'node:test';
+import assert from 'node:assert';
+
+import { createConnection } from '../../../../promise.js';
+
+describe('Binary Parser Timezone Sanitization', () => {
+  it('should reject malicious timezone with code injection', async () => {
+    try {
+      const connection = await createConnection({
+        host: '127.0.0.1',
+        user: 'root',
+        timezone: "'+process.exit(1)+'",
+      });
+      // If we get here, close the connection and fail
+      await connection.end();
+      assert.fail('Should have thrown an error for malicious timezone');
+    } catch (err) {
+      assert.ok(
+        err.message.includes('Invalid timezone option value'),
+        `Expected timezone validation error, got: ${err.message}`
+      );
+    }
+  });
+
+  it('should accept valid positive offset timezone', async () => {
+    // This test only validates that the timezone passes sanitization
+    // It may fail on connection if no server is available, which is fine
+    try {
+      const connection = await createConnection({
+        host: '127.0.0.1',
+        user: 'root',
+        timezone: '+05:30',
+      });
+      await connection.end();
+    } catch (err) {
+      // Connection errors are acceptable; timezone validation errors are not
+      assert.ok(
+        !err.message.includes('Invalid timezone option value'),
+        `Valid timezone was rejected: ${err.message}`
+      );
+    }
+  });
+
+  it('should accept valid negative offset timezone', async () => {
+    try {
+      const connection = await createConnection({
+        host: '127.0.0.1',
+        user: 'root',
+        timezone: '-05:00',
+      });
+      await connection.end();
+    } catch (err) {
+      assert.ok(
+        !err.message.includes('Invalid timezone option value'),
+        `Valid timezone was rejected: ${err.message}`
+      );
+    }
+  });
+});
